#import "DYYYNativeTabIcons.h"

// Extracted without redrawing from Instagram 435.1.0's
// FBSharedFramework.framework/Assets.car. The source renditions are:
// ig_icon_home_pano_prism_{outline,filled}_24,
// ig_icon_reels_{outline,filled}_24,
// ig_icon_direct_{outline,filled}_24, and
// ig_icon_user_circle_prism_{outline,filled}_24.
static UIImage *DYYYTemplateImage(NSString *base64) {
    NSData *data = [[NSData alloc] initWithBase64EncodedString:base64 options:0];
    UIImage *image = [[UIImage alloc] initWithData:data scale:2.0];
    return [image imageWithRenderingMode:UIImageRenderingModeAlwaysTemplate];
}

UIImage *DYYYNativeTabIcon(DYYYNativeTabIconKind kind, BOOL selected) {
    static NSArray<UIImage *> *icons;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
      icons = @[
          DYYYTemplateImage(@""),
          DYYYTemplateImage(@""),
          DYYYTemplateImage(@""),
          DYYYTemplateImage(@""),
          DYYYTemplateImage(@""),
          DYYYTemplateImage(@""),
          DYYYTemplateImage(@""),
          DYYYTemplateImage(@""),
      ];
    });

    if (kind == DYYYNativeTabIconKindUnknown) {
        return nil;
    }
    NSUInteger index = kind * 2 + (selected ? 1 : 0);
    return index < icons.count ? icons[index] : nil;
}
